INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 112029, 0.5, 10, 112, 1, "ランドソルを囲む壁に絵を？\nふぅん、楽しそうね。\nここに描けばいいのかしら？", 106431, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 112030, "", "", 112, "", "", 112029, 91);
