INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 112039, 0.5, 10, 112, 1, "え？　ランドソルの壁を……\nぐるっと一周？", 106431, 11);
