INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 112064, 0.5, 10, 112, 1, "待って待って待って！！\n待ちなさいってば！？\nあんたたち、ランドソルの壁一周って\nどんだけの長さがあると思ってんのよ！", 106011, 11);
