INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 8512022, 0.5, 10, 8512, 1, "で～きた！\nどうかな、クルミ？\n筆使い？　が大胆すぎるかな？", 102311, 11);
