INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 8512027, 0.5, 10, 8512, 1, "そんなことないよ、アヤネちゃん……！\nすっごく元気が出てくるような絵で\n私は、大好きだよ……♪", 102111, 11);
