INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 8612022, 0.5, 10, 8612, 1, "ふふ、こうしてみなさまと一緒に\n絵を描くというのもまた\n楽しいものでございますね。", 105911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 8612023, "", "", 8612, "", "", 0, 91);
