INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 8612027, 0.5, 10, 8612, 1, "そうね。慣れないせいもあって\n緊張しちゃうけど、\nコッコロさんやみんなが一緒だと\n落ち着いて、楽しくやれる気がするわ。", 106411, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 8612028, "", "", 8612, "", "", 0, 91);
