INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112024, "", 0, 14112, 0, "vo_wac_220705_000", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112025, 0.5, 10, 14112, 1, "やった！　これにて完成でござるよ～！\nう～ん、色使いといい、タッチといい、\n今度も素晴らしい出来栄えですな～！", 101311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112026, "", "", 14112, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112027, "", 1, 14112, "", "wac_idle_wish", 101311, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112028, "", 0, 14112, "wac_talk_smile_loop_L", "wac_talk_smile_in_L", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112029, "", 0, 14112, 0, "vo_wac_220705_001", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112030, 0.5, 10, 14112, 1, "上出来、上出来。\nさて、絵も完成したことだし、\nみんなでパパっと片づけをして\n食事にでも行くとするかい。", 105611, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112031, "", "", 14112, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112032, "", 1, 14112, "", "wac_idle_smile_L", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112033, "", 0, 14112, "wac_talk_doya_loop", "wac_talk_doya_in", 105111, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112034, "", 0, 14112, 0, "vo_wac_220705_002", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112035, 0.5, 10, 14112, 1, "あら？　でも……\n片づけはもう済んでるみたいよ？\nうふふ、いったいどこの「いい子」が\nやってくれたのかしらね～？", 105111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112036, "", "", 14112, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112037, "", 1, 14112, "", "wac_idle_doya", 105111, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112038, "", 0, 14112, "wac_talk_smile_loop_L", "wac_talk_smile_in_L", 102711, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112039, "", 0, 14112, 0, "vo_wac_220705_003", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112040, 0.5, 10, 14112, 1, "クスクス……私は見ていましたよ。\nアンナさん、あなたがいそいそと\n後ろで道具を片づけているのを……", 102711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112041, "", "", 14112, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112042, "", 1, 14112, "", "wac_idle_smile_L", 102711, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112043, "", 0, 14112, "wac_talk_doya_loop_L", "wac_talk_doya_in_L", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112044, "", 0, 14112, 0, "vo_wac_220705_004", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112045, 0.5, 10, 14112, 1, "はは、そりゃ助かった。\nお前さん、物言いは突飛だが、\nそういうところにはよく気が回るねえ。\nいい子じゃないか。", 105611, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112046, "", "", 14112, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 14112047, "", 1, 14112, "", "wac_idle_smile_L", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0.2, 14112048, "", 1, 14112, "", "wac_talk_anger", 100911, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112049, "", 0, 14112, 0, "vo_wac_220705_005", "vo_wac_220705", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14112050, 0.5, 10, 14112, 1, "なっ、いい子とか言うなぁ！\nて、手がすいたからやっただけで、\nそこはせめて全知全能と……\nうぅ、生暖かい目で見るなぁっ！", 100911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14112051, "", "", 14112, "", "", 0, 91);
