INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14312022, 0.5, 10, 14312, 1, "ふふ、絵を描くのって楽しいさ～！\n描いても描いても飽きないし……\n歌って踊ればもっと楽しくなるさ～！", 101711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14312023, "", "", 14312, "", "", 0, 91);
