INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 14712036, 0.5, 10, 14712, 1, "なにをバカなことを……\nあなた様への愛をありったけ\n詰め込んだ、私の絵こそが\n一番の傑作に決まってます……", 102711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 14712037, "", "", 14712, "", "", 0, 91);
