INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16112022, "", 0, 16112, 0, "vo_wac_220725_001", "vo_wac_220725", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16112023, 0.5, 10, 16112, 1, "うわあ！　マスターってば\n絵も上手なんですね！　でも\n言い方がお婆ちゃんみたいですよ？\nなるほど、これが亀の甲羅で逃避行！", 101111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16112024, "", "", 16112, "", "", 0, 91);
