INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16112028, 0.5, 10, 16112, 1, "リノちゃん、こーら☆\nそんな言い方失礼だよ？\nマスターはいつも忙しくて\n大変なんだから。", 104911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16112029, "", "", 16112, "", "", 0, 91);
