INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16412030, 0.5, 10, 16412, 1, "シュバッ！　シュバババッ！\n色塗りはワタシにお任せデース！\nこの絵筆二刀流で、瞬く間に\nカラフルにしてみせマース！", 103011, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16412031, "", "", 16412, "", "", 0, 91);
