INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16412035, 0.5, 10, 16412, 1, "絵の下書きはボクに任せて。\nすべての美しさの源になる存在……\nそれがボクだからね！", 100811, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16412036, "", "", 16412, "", "", 0, 91);
