INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16412045, 0.5, 10, 16412, 1, "あっ、道具のお片づけは\n私がしておきました……\nこういう地味な作業でも、\nお役に立ててるといいんですけど……", 105511, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16412046, "", "", 16412, "", "", 0, 91);
