INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612025, "", 0, 16612, 0, "vo_wac_220730_000", "vo_wac_220730", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16612026, 0.5, 10, 16612, 1, "ふふ、やった！　やったぞ！\nまたしても傑作の完成だ！\nみんなの努力が実る、この瞬間……\n何度やっても達成感があるな！", 100911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612027, "", "", 16612, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612028, "", 1, 16612, "", "wac_idle_kyapi_L", 100911, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612029, "", 0, 16612, "wac_talk_sad_loop", "wac_talk_sad_in", 102711, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612030, "", 0, 16612, 0, "vo_wac_220730_001", "vo_wac_220730", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16612031, 0.5, 10, 16612, 1, "ちょ、ちょっとアンナさん……\nあなた全身、絵の具だらけで\n動くたびに飛び散ってますわ。\n少し大人しくしてもらえますか？", 102711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612032, "", "", 16612, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612033, "", 1, 16612, "", "wac_idle_sad", 102711, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612034, "", 0, 16612, "wac_talk_smile_loop", "wac_talk_smile_in", 101311, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612035, "", 0, 16612, 0, "vo_wac_220730_002", "vo_wac_220730", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16612036, 0.5, 10, 16612, 1, "あははっ！　そういうエリコ様も\nおててが絵の具だらけでござるよ～！\nむふふ、いわゆるギャップ萌え\nというやつですな？", 101311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612037, "", "", 16612, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612038, "", 1, 16612, "", "wac_idle_smile", 101311, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0.2, 16612039, "", 1, 16612, "", "wac_talk_surprise_loop_shy", 105111, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612040, "", 0, 16612, 0, "vo_wac_220730_003", "vo_wac_220730", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16612041, 0.5, 10, 16612, 1, "まったくもう……\nみんなして絵の具まみれじゃない。\nって、あら？　この赤いのは……", 105111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612042, "", "", 16612, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612043, "", 1, 16612, "", "wac_idle_sad", 105111, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 16612044, "", 0, 16612, "wac_talk_smile_loop_L", "wac_talk_smile_in_L", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612045, "", 0, 16612, 0, "vo_wac_220730_004", "vo_wac_220730", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 16612046, 0.5, 10, 16612, 1, "ふふ、そういうアンタも、\nほっぺに絵の具がついてるじゃないか。\nほら、きれいにしてやるから\nそこに並びな、アンタたち。", 105611, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 16612047, "", "", 16612, "", "", 0, 91);
