INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 17812022, 0.5, 10, 17812, 1, "これで担当分はおしまいかな？\n剣術も芸術も、雑念を振り払い、\n一意専心に取り組むのが\nうまくいくコツな気がするよ。", 103711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 17812023, "", "", 17812, "", "", 0, 91);
