INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 17812027, 0.5, 10, 17812, 1, "トモちゃんは真面目だね。\n私は絵の具が鎧にはねたら\nどうしようって、そればかり\n考えていたよ。", 104711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 17812028, "", "", 17812, "", "", 0, 91);
