INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 17812031, "", 0, 17812, 0, "vo_wac_220811_002", "vo_wac_220811", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 17812032, 0.5, 10, 17812, 1, "自分は、トラタイガーの\nことを考えながら描いてたッス！\n正義のヒーローへの憧れと情熱を、\nランドソルの壁に叩きつけたッス！", 100511, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 17812033, "", "", 17812, "", "", 0, 91);
