INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 18812026, 0.5, 10, 18812, 1, "完☆成！\nぐうかわ魔法少女が描く、\nこれまたぐうかわな壁画をご覧あれ～！\nテーマは……努力！　友情！　勝利！", 101311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812027, "", "", 18812, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 18812028, "", 1, 18812, "", "wac_idle_kyapi", 101311, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 18812029, "", 0, 18812, "wac_talk_doya_loop_surprise_L", "wac_talk_doya_in_surprise_L", 100911, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812030, "", 0, 18812, 0, "vo_wac_220821_001", "vo_wac_220821", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 18812031, 0.5, 10, 18812, 1, "むっ、ちょっと待て。\nこの絵のテーマは、繰り返される\n運命の闘争が織りなす限りなき\nウロボロスの循環ではないのか！？", 100911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812032, "", "", 18812, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 18812033, "", 1, 18812, "", "wac_idle_doya_surprise_L", 100911, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 18812034, "", 0, 18812, "wac_talk_wish_loop_L", "wac_talk_wish_in_L", 102711, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812035, "", 0, 18812, 0, "vo_wac_220821_002", "vo_wac_220821", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 18812036, 0.5, 10, 18812, 1, "クスクス……違います。\nこれはあのおかたへの愛……\n枯れることのない、永遠の愛が\nテーマですわ……", 102711, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812037, "", "", 18812, "", "", 0, 91);
