INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 18812044, "", 0, 18812, "wac_talk_arm_crossed_loop", "wac_talk_arm_crossed_in", 105611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 18812045, "", 0, 18812, 0, "vo_wac_220821_004", "vo_wac_220821", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 18812046, 0.5, 10, 18812, 1, "いやいや、それであってるよ。\nアイツら、やる気満々なのはいいけど、\n余計なもん描き足してないだろうね？\nあとで見ておくか……", 105611, 11);
