INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 19812032, "", 0, 19812, "wac_talk_sad_loop_L", "wac_talk_sad_in_L", 105311, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 19812033, "", 0, 19812, 0, "vo_wac_220831_001", "vo_wac_220831", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 19812034, 0.5, 10, 19812, 1, "いや、浮世絵って\nこんな感じだったか？\nオーエドで見たのは、もう少し\n違う雰囲気だった気がするのだが。", 105311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 19812035, "", "", 19812, "", "", 0, 91);
