INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 19812043, "", 0, 19812, 0, "vo_wac_220831_003", "vo_wac_220831", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 19812044, 0.5, 10, 19812, 1, "そ、そうですね……\nドＳさんも多種多様な攻めを\n繰り出してきますけど、全部\nクウカにとっては快感ですし。", 104511, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 19812045, "", "", 19812, "", "", 0, 91);
