INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 19812049, 0.5, 10, 19812, 1, "それは流石に違う気がします……\nでも、みんなで描いた絵が、\n浮世絵みたいにきれいに\nできたのはそのとおりですね♪", 105511, 11);
