INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 23212022, 0.5, 10, 23212, 1, "ふぅ、これでできあがりね。\nみんなもすごく上手に描けてるし、\nよく頑張ったわね♪", 102811, 11);
