INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 23812034, "", 0, 23812, "wac_talk_doya_loop_surprise_L", "wac_talk_doya_in_surprise_L", 103011, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 23812035, "", 0, 23812, 0, "vo_wac_221010_002", "vo_wac_221010", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 23812036, 0.5, 10, 23812, 1, "オー、まさに陰と陽！\nこれがゲージュツの分野で\nいうところの、コントラストと\nいうヤツなのでショウか？", 103011, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 23812037, "", "", 23812, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 23812038, "", 1, 23812, "", "wac_idle_doya_surprise_L", 103011, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 23812039, "", 0, 23812, "wac_talk_sad_loop_L", "wac_talk_sad_in_L", 105511, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 23812040, "", 0, 23812, 0, "vo_wac_221010_003", "vo_wac_221010", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 23812041, 0.5, 10, 23812, 1, "絶対に違うと思います……\n二人とも、自分の好きなものに\n忠実なだけというか……", 105511, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 23812042, "", "", 23812, "", "", 0, 91);
