INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 23812046, 0.5, 10, 23812, 1, "ほら、いつまでも壁の前で\nダラダラしてないで帰るぞ！\n私たちに必要なのは、尊さだの\n芸術だのではなく、訓練なんだからな！", 105311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 23812047, "", "", 23812, "", "", 0, 91);
