INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 25712009, 0.5, 10, 25712, 1, "また一つ、かわいいボクに\nよって美しい芸術が完成\nしてしまったよ……天はボクに、\nいくつ才能を与えるつもりなのかな？", 100811, 11);
