INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", 0.2, 26212030, "", 1, 26212, "", "wac_talk_wish_loop", 103811, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 26212031, "", 0, 26212, 0, "vo_wac_221103_002", "vo_wac_221103", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 26212032, 0.5, 10, 26212, 1, "実は、ちょっとだけ\nフラフラ～ってしてます……\nみんなでお絵描きするのが楽しくて、\nはしゃぎすぎちゃったみたいで……", 103811, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 26212033, "", "", 26212, "", "", 0, 91);
