INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812030, "", 0, 27812, 0, "vo_wac_221119_001", "vo_wac_221119", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 27812031, 0.5, 10, 27812, 1, "おぉー、クウカがひいた曲線、\nすごくきれいデス！\nまるでウキヨエマスターみたいデスね！\nワタシにもその技、教えてクダサイ！", 103011, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812032, "", "", 27812, "", "", 0, 91);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 27812033, "", 1, 27812, "", "wac_idle_doya_L", 103011, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 27812034, "", 0, 27812, "wac_talk_sad_loop_surprise", "wac_talk_sad_in_surprise", 105511, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812035, "", 0, 27812, 0, "vo_wac_221119_002", "vo_wac_221119", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 27812036, 0.5, 10, 27812, 1, "ニ、ニノンさんも上手でしたけど、\nクウカさんもすごい……！\nでも、クウカさんが興奮してるのは、\n違う理由のような……", 105511, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812037, "", "", 27812, "", "", 0, 91);
