INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812040, "", 0, 27812, 0, "vo_wac_221119_003", "vo_wac_221119", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 27812041, 0.5, 10, 27812, 1, "うむ……もはや、何も言うまい。\nしかし共同作戦というのは悪くないな。\nこれはチームプレイの\n良い訓練になるぞ！", 105311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 27812042, "", "", 27812, "", "", 0, 91);
