INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 28412031, "", 0, 28412, 0, "vo_wac_221125_002", "vo_wac_221125", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 28412032, 0.5, 10, 28412, 1, "このクリスティーナが手伝う以上、\n粗い仕事など許さん！\nまったく、オマエたちはもう少し、\n芸術を嗜むべきだぞ♪", 107111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 28412033, "", "", 28412, "", "", 0, 91);
