INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 31112026, 0.5, 10, 31112, 1, "……できました。\n「皆さん」のお力添えもあって、\nずいぶんと早く仕上がりましたね。", 103111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 31112027, "", "", 31112, "", "", 0, 91);
