INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 31112031, 0.5, 10, 31112, 1, "うん！\n……でも、このあたりって\n誰が色塗り担当だったっけ？\n気づいたら塗り終わってたよね？", 100611, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 31112032, "", "", 31112, "", "", 0, 91);
