INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 34312026, 0.5, 10, 34312, 1, "できたの～！\n今回もよく描けたから、\n当然の権利としてプリンを\n要求するの、早く出せなの。", 100711, 11);
