INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 35812022, 0.5, 10, 35812, 1, "むっ……おい、マツリちゃん。\nしっぽの先がペンキで汚れているぞ。\nどれ、ワタシが丁寧に拭ってやろう♪", 107111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 35812023, "", "", 35812, "", "", 0, 91);
