INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 36912032, 0.5, 10, 36912, 1, "もちろん、この絵だけじゃないよ？\nこれからは一緒に、いろいろ\n楽しいことに挑戦していこ～♪", 100111, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 36912033, "", "", 36912, "", "", 0, 91);
