INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 37912031, 0.5, 10, 37912, 1, "「ドッキリ大成功です！」つってね。\nプラカードと国家予算持ってね。\nあるある、絶対ソレだわ。", 110811, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 37912032, "", "", 37912, "", "", 0, 91);
