INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 38612031, 0.5, 10, 38612, 1, "でも、楽しいお仕事ですぞ～♪\nできればもうすこ～し、\n魔法少女チックな要素を\n付け足せたらとは思ったけど……", 101311, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 38612032, "", "", 38612, "", "", 0, 91);
