INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 38612036, 0.5, 10, 38612, 1, "いや、どうせ付け足すのならば\nこの疾風の冥姫がいかにして\n呪われし運命を克服していったか、\nその神話が分かるような壁画を……", 100911, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 38612037, "", "", 38612, "", "", 0, 91);
