INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 38612041, 0.5, 10, 38612, 1, "いいえ……運命の物語を描くなら、\n私とあなた様との出会いから今までを\n描いた方が素敵ですわよね……\nクスクス……♪", 102711, 11);
