INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", 1, 0.2, 39512030, "", 0, 39512, "wac_talk_sad_loop_surprise_L", "wac_talk_sad_in_surprise_L", 104611, 3);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 39512031, "", 0, 39512, 0, "vo_wac_230316_002", "vo_wac_230316", 21);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 39512032, 0.5, 10, 39512, 1, "もう既に二日酔いになってるにゃ。\n麦しゅわを飲んだことがないから、\nユカリがひたすら麦しゅわを\n求める気持ちが分かんないにゃ。", 104611, 11);
INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES ("", "", "", 39512033, "", "", 39512, "", "", 0, 91);
