INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 40922014, 0.5, 10, 40922, 1, "そうでございますね。\n【美食殿】だけでなく、多くのギルドの\nみなさまが力を合わせた結果、\n美しい壁になったのだと思います。", 105911, 11);
