INSERT INTO `v1_bce4c454187e3576a072cfcc9f91db22e414d4443815f95546a1965fa6219898` VALUES (0, 1, 0, 40922019, 0.5, 10, 40922, 1, "私たち自身にとっても、\n素敵な思い出になったと思うわ。\nこうして形に残るお仕事なら、また\nいつか……見に来ることもできるし。", 106411, 11);
